#include <iostream>

void describe(int x) {
    std::cout << "Integer: " << x << "\n";
}

void describe(double x) {
    std::cout << "Double: " << x << "\n";
}

int main() {
    int n;
    double d;
    std::cin >> n >> d;
    describe(n);
    describe(d);
    return 0;
}

